import{_ as s,c as a,e,o as p}from"./app-BE7TiTFj.js";const t={};function o(i,n){return p(),a("div",null,[...n[0]||(n[0]=[e(`<h1 id="kratos微服务与它的小伙伴系列-依赖注入库-wire" tabindex="-1"><a class="header-anchor" href="#kratos微服务与它的小伙伴系列-依赖注入库-wire"><span>Kratos微服务与它的小伙伴系列 - 依赖注入库 - Wire</span></a></h1><h2 id="什么是依赖注入" tabindex="-1"><a class="header-anchor" href="#什么是依赖注入"><span>什么是依赖注入？</span></a></h2><p>依赖注入 (Dependency Injection，缩写为 DI)，是一种软件设计模式，也是实现控制反转(Inversion of Control)的其中一种技术。这种模式能让一个物件接收它所依赖的其他物件。“依赖”是指接收方所需的对象。“注入”是指将“依赖”传递给接收方的过程。在“注入”之后，接收方才会调用该“依赖”。此模式确保了任何想要使用给定服务的物件不需要知道如何建立这些服务。取而代之的是，连接收方物件（像是 client）也不知道它存在的外部代码（注入器）提供接收方所需的服务。</p><p>依赖注入涉及四个概念：</p><ol><li>服务：任何类，提供了有用功能。</li><li>客户：使用服务的类。</li><li>接口：客户不应该知道服务实现的细节，只需要知道服务的名称和 API。</li><li>注入器：Injector，也称 assembler、container、provider 或 factory。负责把服务引入给客户。 依赖注入把对象构建与对象注入分开。因此创建对象的 new 关键字也可消失了。</li></ol><p>Golang 的依赖注入框架有两类：</p><ul><li>通过反射在运行时进行依赖注入，典型代表是 <strong>Uber</strong> 开源的 <a href="https://github.com/uber-go/dig" target="_blank" rel="noopener noreferrer">dig</a>；</li><li>通过 <code>generate</code> 进行代码生成，典型代表是 <strong>Google</strong> 开源的 <a href="https://github.com/google/wire" target="_blank" rel="noopener noreferrer">wire</a>。</li></ul><p>使用 dig 功能会强大一些，但是缺点就是错误只能在运行时才能发现，这样如果不小心的话可能会导致一些隐藏的 bug 出现。使用 wire 的缺点就是功能限制多一些，但是好处就是编译的时候就可以发现问题，并且生成的代码其实和我们自己手写相关代码差不太多，更符合直觉，心智负担更小，所以更加推荐 wire。</p><h2 id="什么是wire" tabindex="-1"><a class="header-anchor" href="#什么是wire"><span>什么是Wire？</span></a></h2><p><a href="https://github.com/google/wire" target="_blank" rel="noopener noreferrer">wire</a> 是由 google 开源的一个供 Go 语言使用的依赖注入代码生成工具。它能够根据你的代码，生成相应的依赖注入 go 代码。</p><p>与其他依赖注入工具不同，比如 Uber 的 Dig 和 Facebook 的 Inject，这 2 个工具都是使用反射实现的依赖注入，而且是运行时注入（runtime dependency injection）。</p><p>wire 是编译代码时生成代码的依赖注入，是编译期间注入依赖代码（compile-time dependency injection）。而且代码生成期间，如果依赖注入有问题，生成依赖代码时就会出错，就可以报出问题来，而不必等到代码运行时才暴露出问题。</p><h2 id="provider-和-injector" tabindex="-1"><a class="header-anchor" href="#provider-和-injector"><span>Provider 和 Injector</span></a></h2><p>首先，需要理解 wire 的 2 个核心概念：provider 和 injector。</p><p>从上面 Java 模拟依赖注入的例子中，可以简化出依赖注入的步骤：</p><ul><li>第一：需要 New 出一个类实例</li><li>第二：把这个 New 出来的类实例通过构造函数或者其他方式“注入”到需要使用它的类中</li><li>第三：在类中使用这个 New 出来的实例</li></ul><p>从上面步骤来理解 wire 的 2 个核心概念 provider 和 injector。</p><ul><li>provider 就相当于上面 New 出来的类实例。</li><li>injector 就相当于“注入”动作前，把所需依赖函数进行聚合，根据这个聚合的函数生成依赖关系。</li></ul><p>provider：提供一个对象。<br> injector：负责根据对象依赖关系，生成新程序。</p><h3 id="provider" tabindex="-1"><a class="header-anchor" href="#provider"><span>Provider</span></a></h3><p>Provider 是一个普通的 Go 函数 ，可以理解为是一个对象的构造函数。为下面生成 Injector 函数提供”构件“。</p><p>下面的 NewUserStore() 函数可以看作是一个 provider。这个函数需要传入 <code>*Config</code> 和 <code>*mysql.DB</code> 2 个参数。</p><div class="language-Go line-numbers-mode" data-highlighter="prismjs" data-ext="Go"><pre><code><span class="line">// NewUserStore 是一个 provider for *UserStore，*UserStore 依赖 *Config，*mysql.DB</span>
<span class="line">func NewUserStore(cfg *Config, db *mysql.DB) (*UserStore, error) {... ...}</span>
<span class="line"></span>
<span class="line">// NewDefaultConfig 是一个 provider for *Config，没有任何依赖</span>
<span class="line">func NewDefaultConfig() *Config {...}</span>
<span class="line"></span>
<span class="line">// NewDB 是 *mysql.DB 的一个 provider ，依赖于数据库连接信息 *ConnectionInfo</span>
<span class="line">func NewDB(info *ConnectionInfo) (*mysql.DB, error){...}</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>provider 可以组合成一组 provider set。对于经常在一起使用的 providers 来说，这个非常有用。使用 <code>wire.NewSet</code> 方法可以把他们组合在一起，</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">var</span> SuperSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span>NewUserStore<span class="token punctuation">,</span> NewDefaultConfig<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>你也可以把其他的 provider sets 加入一个 provider set，</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">import</span> （</span>
<span class="line">    “example<span class="token punctuation">.</span>com<span class="token operator">/</span>some<span class="token operator">/</span>other<span class="token operator">/</span>pkg”</span>
<span class="line">）</span>
<span class="line"></span>
<span class="line"><span class="token comment">// ... ...</span></span>
<span class="line"><span class="token keyword">var</span> MegaSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span>SuperSet<span class="token punctuation">,</span> pkg<span class="token punctuation">.</span>OtherSet<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>wire.NewSet() 函数：<br> 这个函数可以把相关的 provider 组合在一起然后使用。当然也可以单独使用，如 var Provider = wire.NewSet(NewDB)。<br> 这个 NewSet 函数的返回值也可以作为其他 NewSet 函数的参数使用，比如上面的 SuperSet 作为参数使用。</p></blockquote><h3 id="injector" tabindex="-1"><a class="header-anchor" href="#injector"><span>Injector</span></a></h3><p>我们编写程序把这些 providers 组合起来(比如下面例子 initUserStore() 函数)，wire 里的 wire 命令会按照依赖顺序调用 providers 生成更加完整的函数，这个就是 injector。</p><p>首先，编写生成 injector 的签名函数，然后用 wire 命令生成相应的函数。</p><p>例子如下：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// +build wireinject</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">initUserStore</span><span class="token punctuation">(</span>info <span class="token operator">*</span>ConnectionInfo<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>UserStore<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    wire<span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span>SuperSet<span class="token punctuation">,</span> NewDB<span class="token punctuation">)</span> <span class="token comment">// 声明获取 UserStore 需要调用哪些 provider 函数</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后用 wire 命令把上面的 <code>initUserStore</code> 函数生成 injector 函数，生成的函数对应文件名 <code>wire_gen.go</code>。</p><blockquote><p>wire 命令:</p><p>You can generate the injector by invoking Wire in the package directory。<br> 直接在生成 injector 函数的包下，使用 wire 命令，就可以生成 injector 代码。</p><p>wire.Build() 函数：</p><p>它的参数可以是 wire.NewSet() 组织的一个或多个 provider，也可以直接使用 provider。</p></blockquote><h2 id="与kratos携起手来" tabindex="-1"><a class="header-anchor" href="#与kratos携起手来"><span>与Kratos携起手来</span></a></h2><h3 id="wire命令行工具安装" tabindex="-1"><a class="header-anchor" href="#wire命令行工具安装"><span>Wire命令行工具安装</span></a></h3><p>使用以下命令将Wire的命令行工具安装在全局路径下，用于代码的生成。</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">go <span class="token function">install</span> github.com/google/wire/cmd/wire@latest</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="场景代码" tabindex="-1"><a class="header-anchor" href="#场景代码"><span>场景代码</span></a></h3><p>在这里，我们做一个“用户服务”。</p><p>根据Kratos的官方推荐Layout，我们将服务分为以下几层：server、service、biz、data。</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> server</span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewHTTPServer</span><span class="token punctuation">(</span>c <span class="token operator">*</span>conf<span class="token punctuation">.</span>Server<span class="token punctuation">,</span> ac <span class="token operator">*</span>conf<span class="token punctuation">.</span>Auth<span class="token punctuation">,</span> logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">,</span> userSvc <span class="token operator">*</span>service<span class="token punctuation">.</span>UserService<span class="token punctuation">)</span> <span class="token operator">*</span>http<span class="token punctuation">.</span>Server <span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">var</span> opts <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>http<span class="token punctuation">.</span>ServerOption<span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line">	<span class="token keyword">if</span> c<span class="token punctuation">.</span>Http<span class="token punctuation">.</span>Network <span class="token operator">!=</span> <span class="token string">&quot;&quot;</span> <span class="token punctuation">{</span></span>
<span class="line">		opts <span class="token operator">=</span> <span class="token function">append</span><span class="token punctuation">(</span>opts<span class="token punctuation">,</span> http<span class="token punctuation">.</span><span class="token function">Network</span><span class="token punctuation">(</span>c<span class="token punctuation">.</span>Http<span class="token punctuation">.</span>Network<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line">	<span class="token keyword">if</span> c<span class="token punctuation">.</span>Http<span class="token punctuation">.</span>Addr <span class="token operator">!=</span> <span class="token string">&quot;&quot;</span> <span class="token punctuation">{</span></span>
<span class="line">		opts <span class="token operator">=</span> <span class="token function">append</span><span class="token punctuation">(</span>opts<span class="token punctuation">,</span> http<span class="token punctuation">.</span><span class="token function">Address</span><span class="token punctuation">(</span>c<span class="token punctuation">.</span>Http<span class="token punctuation">.</span>Addr<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line">	<span class="token keyword">if</span> c<span class="token punctuation">.</span>Http<span class="token punctuation">.</span>Timeout <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">		opts <span class="token operator">=</span> <span class="token function">append</span><span class="token punctuation">(</span>opts<span class="token punctuation">,</span> http<span class="token punctuation">.</span><span class="token function">Timeout</span><span class="token punctuation">(</span>c<span class="token punctuation">.</span>Http<span class="token punctuation">.</span>Timeout<span class="token punctuation">.</span><span class="token function">AsDuration</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line">	srv <span class="token operator">:=</span> http<span class="token punctuation">.</span><span class="token function">NewServer</span><span class="token punctuation">(</span>opts<span class="token operator">...</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">	v1<span class="token punctuation">.</span><span class="token function">RegisterUserServiceHTTPServer</span><span class="token punctuation">(</span>srv<span class="token punctuation">,</span> userSvc<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">return</span> srv</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> service</span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> UserService <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">	v1<span class="token punctuation">.</span>UnimplementedUserServiceServer</span>
<span class="line"></span>
<span class="line">	uc  <span class="token operator">*</span>biz<span class="token punctuation">.</span>UserUseCase</span>
<span class="line">	log <span class="token operator">*</span>log<span class="token punctuation">.</span>Helper</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewUserService</span><span class="token punctuation">(</span>logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">,</span> uc <span class="token operator">*</span>biz<span class="token punctuation">.</span>UserUseCase<span class="token punctuation">)</span> <span class="token operator">*</span>UserService <span class="token punctuation">{</span></span>
<span class="line">	l <span class="token operator">:=</span> log<span class="token punctuation">.</span><span class="token function">NewHelper</span><span class="token punctuation">(</span>log<span class="token punctuation">.</span><span class="token function">With</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> <span class="token string">&quot;module&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;service/user&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token keyword">return</span> <span class="token operator">&amp;</span>UserService<span class="token punctuation">{</span></span>
<span class="line">		log<span class="token punctuation">:</span> l<span class="token punctuation">,</span></span>
<span class="line">		uc<span class="token punctuation">:</span>  uc<span class="token punctuation">,</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> biz</span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> UserRepo <span class="token keyword">interface</span> <span class="token punctuation">{</span></span>
<span class="line">	<span class="token function">Create</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> req <span class="token operator">*</span>v1<span class="token punctuation">.</span>RegisterRequest<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>v1<span class="token punctuation">.</span>User<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token function">Update</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> req <span class="token operator">*</span>v1<span class="token punctuation">.</span>UpdateUserRequest<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>v1<span class="token punctuation">.</span>User<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token function">Delete</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> req <span class="token operator">*</span>v1<span class="token punctuation">.</span>DeleteUserRequest<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token builtin">bool</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> UserUseCase <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">	repo UserRepo</span>
<span class="line">	log  <span class="token operator">*</span>log<span class="token punctuation">.</span>Helper</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewUserUseCase</span><span class="token punctuation">(</span>repo UserRepo<span class="token punctuation">,</span> logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">)</span> <span class="token operator">*</span>UserUseCase <span class="token punctuation">{</span></span>
<span class="line">	l <span class="token operator">:=</span> log<span class="token punctuation">.</span><span class="token function">NewHelper</span><span class="token punctuation">(</span>log<span class="token punctuation">.</span><span class="token function">With</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> <span class="token string">&quot;module&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;user/usecase&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token keyword">return</span> <span class="token operator">&amp;</span>UserUseCase<span class="token punctuation">{</span></span>
<span class="line">		repo<span class="token punctuation">:</span> repo<span class="token punctuation">,</span></span>
<span class="line">		log<span class="token punctuation">:</span>  l<span class="token punctuation">,</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> data</span>
<span class="line"></span>
<span class="line"><span class="token keyword">var</span> <span class="token boolean">_</span> biz<span class="token punctuation">.</span>UserRepo <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token operator">*</span>UserRepo<span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token boolean">nil</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> UserRepo <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">	data <span class="token operator">*</span>Data</span>
<span class="line">	log  <span class="token operator">*</span>log<span class="token punctuation">.</span>Helper</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewUserRepo</span><span class="token punctuation">(</span>data <span class="token operator">*</span>Data<span class="token punctuation">,</span> logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">)</span> biz<span class="token punctuation">.</span>UserRepo <span class="token punctuation">{</span></span>
<span class="line">	l <span class="token operator">:=</span> log<span class="token punctuation">.</span><span class="token function">NewHelper</span><span class="token punctuation">(</span>log<span class="token punctuation">.</span><span class="token function">With</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> <span class="token string">&quot;module&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;user/repo&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token keyword">return</span> <span class="token operator">&amp;</span>UserRepo<span class="token punctuation">{</span></span>
<span class="line">		data<span class="token punctuation">:</span> data<span class="token punctuation">,</span></span>
<span class="line">		log<span class="token punctuation">:</span>  l<span class="token punctuation">,</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="没有wire-我们该如何组装代码" tabindex="-1"><a class="header-anchor" href="#没有wire-我们该如何组装代码"><span>没有Wire，我们该如何组装代码？</span></a></h3><p>现在，我们需要把上面这几个包组合起来，常规都是这样写的：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    userRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewUserRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">    userUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewUserUseCase</span><span class="token punctuation">(</span>userRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">    userService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewUserService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> userUseCase<span class="token punctuation">)</span></span>
<span class="line">    httpSrv <span class="token operator">:=</span> server<span class="token punctuation">.</span><span class="token function">NewHTTPServer</span><span class="token punctuation">(</span>confServer<span class="token punctuation">,</span> auth<span class="token punctuation">,</span> logger<span class="token punctuation">,</span> userService<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">	app <span class="token operator">:=</span> kratos<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">Name</span><span class="token punctuation">(</span><span class="token string">&quot;http&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span></span>
<span class="line">			httpSrv<span class="token punctuation">,</span></span>
<span class="line">		<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">	<span class="token punctuation">)</span></span>
<span class="line">	<span class="token keyword">if</span> err <span class="token operator">:=</span> app<span class="token punctuation">.</span><span class="token function">Run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">		log<span class="token punctuation">.</span><span class="token function">Error</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>唔，看起来好像也没有什么啊，我觉着这么写也没啥问题啊。</p><p>是的，如果项目的规模很小的时候，这样写也没啥毛病，而且看起来还挺清晰的。</p><p>那么，我的项目没有这么简单了，突然爆炸了：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line">client <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewEntClient</span><span class="token punctuation">(</span>confData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">redisClient <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewRedisClient</span><span class="token punctuation">(</span>confData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">dataData<span class="token punctuation">,</span> cleanup<span class="token punctuation">,</span> err <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewData</span><span class="token punctuation">(</span>client<span class="token punctuation">,</span> redisClient<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> err</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">userRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewUserRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">userUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewUserUseCase</span><span class="token punctuation">(</span>userRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">userTokenRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewUserTokenRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> auth<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">userTokenUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewUserAuthUseCase</span><span class="token punctuation">(</span>userTokenRepo<span class="token punctuation">)</span></span>
<span class="line">userService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewUserService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> userUseCase<span class="token punctuation">,</span> userTokenUseCase<span class="token punctuation">)</span></span>
<span class="line">postRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewPostRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">postUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewPostUseCase</span><span class="token punctuation">(</span>postRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">postService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewPostService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> postUseCase<span class="token punctuation">)</span></span>
<span class="line">linkRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewLinkRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">linkUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewLinkUseCase</span><span class="token punctuation">(</span>linkRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">linkService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewLinkService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> linkUseCase<span class="token punctuation">)</span></span>
<span class="line">categoryRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewCategoryRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">categoryUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewCategoryUseCase</span><span class="token punctuation">(</span>categoryRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">categoryService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewCategoryService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> categoryUseCase<span class="token punctuation">)</span></span>
<span class="line">commentRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewCommentRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">commentUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewCommentUseCase</span><span class="token punctuation">(</span>commentRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">commentService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewCommentService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> commentUseCase<span class="token punctuation">)</span></span>
<span class="line">tagRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewTagRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">tagUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewTagUseCase</span><span class="token punctuation">(</span>tagRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">tagService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewTagService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> tagUseCase<span class="token punctuation">)</span></span>
<span class="line">attachmentRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewAttachmentRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">attachmentUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewAttachmentUseCase</span><span class="token punctuation">(</span>attachmentRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">attachmentService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewAttachmentService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> attachmentUseCase<span class="token punctuation">)</span></span>
<span class="line">httpServer <span class="token operator">:=</span> server<span class="token punctuation">.</span><span class="token function">NewHTTPServer</span><span class="token punctuation">(</span>confServer<span class="token punctuation">,</span> auth<span class="token punctuation">,</span> logger<span class="token punctuation">,</span> userService<span class="token punctuation">,</span> postService<span class="token punctuation">,</span> linkService<span class="token punctuation">,</span> categoryService<span class="token punctuation">,</span> commentService<span class="token punctuation">,</span> tagService<span class="token punctuation">,</span> attachmentService<span class="token punctuation">)</span></span>
<span class="line">registrar <span class="token operator">:=</span> server<span class="token punctuation">.</span><span class="token function">NewRegistrar</span><span class="token punctuation">(</span>registry<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>现在，你再来看。我就问你，头大不大？脑壳晕不晕？心情美不美丽？</p><p>这是一个圆环套圆环的游戏，你不仅需要手写这么多的代码，而且，还需要管理他们之间的依赖关系，要小心翼翼的别把传入参数搞错、创建的顺序别搞错。</p><p>这时候，我要：增加一个方法，减少一个方法；增加一个变量，减少一个变量。都是很奔溃的事情。哪怕你再小心翼翼，也保不齐自己不出错。</p><h3 id="有了wire-我们可以如何组装代码" tabindex="-1"><a class="header-anchor" href="#有了wire-我们可以如何组装代码"><span>有了Wire，我们可以如何组装代码？</span></a></h3><p>首先需要在上面4个包下面声明4个<code>ProviderSet</code>变量：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> server</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">	<span class="token string">&quot;github.com/google/wire&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// ProviderSet is server providers.</span></span>
<span class="line"><span class="token keyword">var</span> ProviderSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span>NewHTTPServer<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> service</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">	<span class="token string">&quot;github.com/google/wire&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// ProviderSet is service providers.</span></span>
<span class="line"><span class="token keyword">var</span> ProviderSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span></span>
<span class="line">	NewUserService<span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> biz</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token string">&quot;github.com/google/wire&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// ProviderSet is biz providers.</span></span>
<span class="line"><span class="token keyword">var</span> ProviderSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span></span>
<span class="line">	NewUserUseCase<span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> data</span>
<span class="line"></span>
<span class="line"><span class="token comment">// ProviderSet is data providers.</span></span>
<span class="line"><span class="token keyword">var</span> ProviderSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span></span>
<span class="line">	NewData<span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">	NewEntClient<span class="token punctuation">,</span></span>
<span class="line">	NewRedisClient<span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">	NewUserRepo<span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>而现在，main包下面，我需要两个go文件：</p><ul><li>main.go</li></ul><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">newApp</span><span class="token punctuation">(</span>logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">,</span> hs <span class="token operator">*</span>http<span class="token punctuation">.</span>Server<span class="token punctuation">,</span> rr registry<span class="token punctuation">.</span>Registrar<span class="token punctuation">)</span> <span class="token operator">*</span>kratos<span class="token punctuation">.</span>App <span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">return</span> kratos<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">ID</span><span class="token punctuation">(</span>Service<span class="token punctuation">.</span><span class="token function">GetInstanceId</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">Name</span><span class="token punctuation">(</span>Service<span class="token punctuation">.</span>Name<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">Version</span><span class="token punctuation">(</span>Service<span class="token punctuation">.</span>Version<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">Metadata</span><span class="token punctuation">(</span>Service<span class="token punctuation">.</span>Metadata<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">Logger</span><span class="token punctuation">(</span>logger<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span></span>
<span class="line">			hs<span class="token punctuation">,</span></span>
<span class="line">		<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">		kratos<span class="token punctuation">.</span><span class="token function">Registrar</span><span class="token punctuation">(</span>rr<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">	<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    app<span class="token punctuation">,</span> cleanup<span class="token punctuation">,</span> err <span class="token operator">:=</span> <span class="token function">initApp</span><span class="token punctuation">(</span>bc<span class="token punctuation">.</span>Server<span class="token punctuation">,</span> rc<span class="token punctuation">,</span> bc<span class="token punctuation">.</span>Data<span class="token punctuation">,</span> bc<span class="token punctuation">.</span>Auth<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">	<span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line">	<span class="token keyword">defer</span> <span class="token function">cleanup</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">	<span class="token comment">// start and wait for stop signal</span></span>
<span class="line">	<span class="token keyword">if</span> err <span class="token operator">:=</span> app<span class="token punctuation">.</span><span class="token function">Run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">		fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">		<span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>wire.go</li></ul><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">//go:build wireinject</span></span>
<span class="line"><span class="token comment">// +build wireinject</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">	<span class="token string">&quot;/internal/biz&quot;</span></span>
<span class="line">	<span class="token string">&quot;/internal/conf&quot;</span></span>
<span class="line">	<span class="token string">&quot;/internal/data&quot;</span></span>
<span class="line">	<span class="token string">&quot;/internal/server&quot;</span></span>
<span class="line">	<span class="token string">&quot;/internal/service&quot;</span></span>
<span class="line"></span>
<span class="line">	<span class="token string">&quot;github.com/go-kratos/kratos/v2&quot;</span></span>
<span class="line">	<span class="token string">&quot;github.com/go-kratos/kratos/v2/log&quot;</span></span>
<span class="line"></span>
<span class="line">	<span class="token string">&quot;github.com/google/wire&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// initApp init kratos application.</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">initApp</span><span class="token punctuation">(</span><span class="token operator">*</span>conf<span class="token punctuation">.</span>Server<span class="token punctuation">,</span> <span class="token operator">*</span>conf<span class="token punctuation">.</span>Registry<span class="token punctuation">,</span> <span class="token operator">*</span>conf<span class="token punctuation">.</span>Data<span class="token punctuation">,</span> <span class="token operator">*</span>conf<span class="token punctuation">.</span>Auth<span class="token punctuation">,</span> log<span class="token punctuation">.</span>Logger<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>kratos<span class="token punctuation">.</span>App<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">	<span class="token function">panic</span><span class="token punctuation">(</span>wire<span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span>server<span class="token punctuation">.</span>ProviderSet<span class="token punctuation">,</span> data<span class="token punctuation">.</span>ProviderSet<span class="token punctuation">,</span> biz<span class="token punctuation">.</span>ProviderSet<span class="token punctuation">,</span> service<span class="token punctuation">.</span>ProviderSet<span class="token punctuation">,</span> newApp<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后在<code>main</code>包路径下直接运行wire命令:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">$ wire</span>
<span class="line">wire: XXXX: wrote XXXX<span class="token punctuation">\\</span>wire_gen.go</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>该命令将会在<code>main</code>包路径下生成一个<code>wire_gen.go</code>文件：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// Code generated by Wire. DO NOT EDIT.</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">//go:generate go run github.com/google/wire/cmd/wire</span></span>
<span class="line"><span class="token comment">//go:build !wireinject</span></span>
<span class="line"><span class="token comment">// +build !wireinject</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Injectors from wire.go:</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// initApp init kratos application.</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">initApp</span><span class="token punctuation">(</span>confServer <span class="token operator">*</span>conf<span class="token punctuation">.</span>Server<span class="token punctuation">,</span> registry <span class="token operator">*</span>conf<span class="token punctuation">.</span>Registry<span class="token punctuation">,</span> confData <span class="token operator">*</span>conf<span class="token punctuation">.</span>Data<span class="token punctuation">,</span> auth <span class="token operator">*</span>conf<span class="token punctuation">.</span>Auth<span class="token punctuation">,</span> logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>kratos<span class="token punctuation">.</span>App<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">	client <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewEntClient</span><span class="token punctuation">(</span>confData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">	redisClient <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewRedisClient</span><span class="token punctuation">(</span>confData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">	dataData<span class="token punctuation">,</span> cleanup<span class="token punctuation">,</span> err <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewData</span><span class="token punctuation">(</span>client<span class="token punctuation">,</span> redisClient<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">	<span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> err</span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line">	userRepo <span class="token operator">:=</span> data<span class="token punctuation">.</span><span class="token function">NewUserRepo</span><span class="token punctuation">(</span>dataData<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">	userUseCase <span class="token operator">:=</span> biz<span class="token punctuation">.</span><span class="token function">NewUserUseCase</span><span class="token punctuation">(</span>userRepo<span class="token punctuation">,</span> logger<span class="token punctuation">)</span></span>
<span class="line">	userService <span class="token operator">:=</span> service<span class="token punctuation">.</span><span class="token function">NewUserService</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> userUseCase<span class="token punctuation">)</span></span>
<span class="line">	httpServer <span class="token operator">:=</span> server<span class="token punctuation">.</span><span class="token function">NewHTTPServer</span><span class="token punctuation">(</span>confServer<span class="token punctuation">,</span> auth<span class="token punctuation">,</span> logger<span class="token punctuation">,</span> userService<span class="token punctuation">)</span></span>
<span class="line">	registrar <span class="token operator">:=</span> server<span class="token punctuation">.</span><span class="token function">NewRegistrar</span><span class="token punctuation">(</span>registry<span class="token punctuation">)</span></span>
<span class="line">	app <span class="token operator">:=</span> <span class="token function">newApp</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> httpServer<span class="token punctuation">,</span> registrar<span class="token punctuation">)</span></span>
<span class="line">	<span class="token keyword">return</span> app<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token function">cleanup</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>明眼人的你一看就明白了：那些初始化依赖的代码全部都在生成的代码当中了。</p><p>从此，圆环套圆环，你调用我我调用你，依赖管理的这些脏活累活，你再也不需要接触，再也不需要干了，全部都丢给了Wire。</p><p>从此往后，你需要做什么呢？</p><p>维护每一个依赖包下面的<code>ProviderSet</code>，然后运行wire命令。</p><p>比如，我现在需要增加一个GRPC服务器，只需要在<code>ProviderSet</code>里边添加<code>NewGRPCServer</code>方法：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">var</span> ProviderSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span>NewHTTPServer<span class="token punctuation">,</span> NewGRPCServer<span class="token punctuation">,</span> NewRegistrar<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>然后运行wire命令，这时候<code>wire_gen.go</code>文件里边就会增加<code>NewGRPCServer</code>方法的调用。</p><p>再比如，我现在需要在<code>NewHTTPServer</code>方法增加一个变量，<code>ProviderSet</code>此时倒是不需要动的。但是，必须要执行wire命令，重新生成代码。</p><h2 id="注意事项" tabindex="-1"><a class="header-anchor" href="#注意事项"><span>注意事项</span></a></h2><p>wire 不允许不同的注入对象拥有相同的类型。google 官方认为这种情况，是设计上的缺陷。这种情况下，可以通过类型别名来将对象的类型进行区分。</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">func</span> <span class="token function">NewRegistrar</span><span class="token punctuation">(</span>conf <span class="token operator">*</span>conf<span class="token punctuation">.</span>Registry<span class="token punctuation">)</span> registry<span class="token punctuation">.</span>Registrar</span>
<span class="line"></span>
<span class="line"><span class="token keyword">var</span> ProviderSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span>NewRegistrar<span class="token punctuation">,</span> NewRegistrar<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以上的代码是不合法的，会报错<code>ProviderSet has multiple bindings for ***</code>。</p><p>我们可以用下面的方法规避，但是，不建议这么做：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">type</span> RegistrarB registry<span class="token punctuation">.</span>Registrar</span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewRegistrarA</span><span class="token punctuation">(</span>conf <span class="token operator">*</span>conf<span class="token punctuation">.</span>Registry<span class="token punctuation">)</span> registry<span class="token punctuation">.</span>Registrar</span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewRegistrarB</span><span class="token punctuation">(</span>conf <span class="token operator">*</span>conf<span class="token punctuation">.</span>Registry<span class="token punctuation">)</span> RegistrarB</span>
<span class="line"></span>
<span class="line"><span class="token keyword">var</span> ProviderSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span>NewRegistrarA<span class="token punctuation">,</span> NewRegistrarB<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="结语" tabindex="-1"><a class="header-anchor" href="#结语"><span>结语</span></a></h2><p>Wire 是一个强大的依赖注入工具。项目工程化过程中，Wire 可以很好的帮助我们管理依赖关系，协助我们完成复杂对象的构建组装。与此同时，Wire与 Inject 、Dig 等不同的是，Wire只生成代码，而不是使用反射在运行时注入，因此不需要担心会有性能损耗。</p><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料"><span>参考资料</span></a></h2><ol><li><a href="https://github.com/google/wire" target="_blank" rel="noopener noreferrer">Wire Github</a></li><li><a href="https://github.com/uber-go/dig" target="_blank" rel="noopener noreferrer">Dig Github</a></li><li><a href="https://lailin.xyz/post/go-training-week4-wire.html" target="_blank" rel="noopener noreferrer">Go工程化(三) 依赖注入框架 wire</a></li><li><a href="https://farer.org/2021/04/21/go-dependency-injection-wire/" target="_blank" rel="noopener noreferrer">理解一下依赖注入，以及如何用 wire</a></li><li><a href="https://zh.wikipedia.org/wiki/%E4%BE%9D%E8%B5%96%E6%B3%A8%E5%85%A5" target="_blank" rel="noopener noreferrer">依赖注入 - 维基百科</a></li><li><a href="https://www.jamesshore.com/v2/blog/2006/dependency-injection-demystified" target="_blank" rel="noopener noreferrer">Dependency Injection Demystified</a></li><li><a href="https://learnku.com/docs/go-blog/wire/6494" target="_blank" rel="noopener noreferrer">Go Cloud Wire：编译时依赖注入详解</a></li><li><a href="https://www.cnblogs.com/jiujuan/p/16136633.html" target="_blank" rel="noopener noreferrer">golang常用库包：Go依赖注入(DI)工具-wire使用</a></li><li><a href="https://zhuanlan.zhihu.com/p/338926709" target="_blank" rel="noopener noreferrer">Golang依赖注入框架wire使用详解</a></li></ol>`,89)])])}const l=s(t,[["render",o]]),u=JSON.parse('{"path":"/posts/kratos_friend_wire.html","title":"Kratos微服务与它的小伙伴系列 - 依赖注入库 - Wire","lang":"zh-CN","frontmatter":{"date":"2020-01-01T00:00:00.000Z","category":["Go编程"],"tag":["Golang","Go-Kratos"],"sticky":10},"headers":[{"level":2,"title":"什么是依赖注入？","slug":"什么是依赖注入","link":"#什么是依赖注入","children":[]},{"level":2,"title":"什么是Wire？","slug":"什么是wire","link":"#什么是wire","children":[]},{"level":2,"title":"Provider 和 Injector","slug":"provider-和-injector","link":"#provider-和-injector","children":[{"level":3,"title":"Provider","slug":"provider","link":"#provider","children":[]},{"level":3,"title":"Injector","slug":"injector","link":"#injector","children":[]}]},{"level":2,"title":"与Kratos携起手来","slug":"与kratos携起手来","link":"#与kratos携起手来","children":[{"level":3,"title":"Wire命令行工具安装","slug":"wire命令行工具安装","link":"#wire命令行工具安装","children":[]},{"level":3,"title":"场景代码","slug":"场景代码","link":"#场景代码","children":[]},{"level":3,"title":"没有Wire，我们该如何组装代码？","slug":"没有wire-我们该如何组装代码","link":"#没有wire-我们该如何组装代码","children":[]},{"level":3,"title":"有了Wire，我们可以如何组装代码？","slug":"有了wire-我们可以如何组装代码","link":"#有了wire-我们可以如何组装代码","children":[]}]},{"level":2,"title":"注意事项","slug":"注意事项","link":"#注意事项","children":[]},{"level":2,"title":"结语","slug":"结语","link":"#结语","children":[]},{"level":2,"title":"参考资料","slug":"参考资料","link":"#参考资料","children":[]}],"git":{"updatedTime":1774788457000,"contributors":[{"name":"tx7do","username":"tx7do","email":"yanglinbo@gmail.com","commits":2,"url":"https://github.com/tx7do"},{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":1,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"a3e88b19cfead00baa606aa5110b2802dac32768","time":1774788457000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: REBUILD."},{"hash":"1f768f471a53340dc4a6b5b0a1246b87cf1c5d46","time":1663916922000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: edit post."},{"hash":"7ef312d6d0b9b0ee29919f61a6ab091f339c2f37","time":1661738844000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: add posts."}]},"filePathRelative":"posts/kratos_friend_wire.md","excerpt":"\\n<h2>什么是依赖注入？</h2>\\n<p>依赖注入 (Dependency Injection，缩写为 DI)，是一种软件设计模式，也是实现控制反转(Inversion of Control)的其中一种技术。这种模式能让一个物件接收它所依赖的其他物件。“依赖”是指接收方所需的对象。“注入”是指将“依赖”传递给接收方的过程。在“注入”之后，接收方才会调用该“依赖”。此模式确保了任何想要使用给定服务的物件不需要知道如何建立这些服务。取而代之的是，连接收方物件（像是 client）也不知道它存在的外部代码（注入器）提供接收方所需的服务。</p>\\n<p>依赖注入涉及四个概念：</p>\\n<ol>\\n<li>服务：任何类，提供了有用功能。</li>\\n<li>客户：使用服务的类。</li>\\n<li>接口：客户不应该知道服务实现的细节，只需要知道服务的名称和 API。</li>\\n<li>注入器：Injector，也称 assembler、container、provider 或 factory。负责把服务引入给客户。\\n依赖注入把对象构建与对象注入分开。因此创建对象的 new 关键字也可消失了。</li>\\n</ol>"}');export{l as comp,u as data};
